VALUES
  ('heelevel3-6e2f88c7-moex-00062', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '國家成立鹽業公司，販賣國民海洋深層水。下列敘述何者正確？', '["該公司不得主張契約自由", "若其產品發生食安事件，不得請求國家賠償", "國家得以公法法規管制該交易", "該交易應受行政法原則之約束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00063', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依司法院大法官解釋或憲法法庭裁判意旨，下列何者之救濟應提起課予義務訴訟？', '["教師因違反教師法遭聘任學校決定自次一學年起不予續聘", "本國人就其外國籍配偶依法申請入境遭駁回處分", "教師因體罰學生遭決議解聘且4年內不得擔任教師，經主管機關核准", "人民依法請求就國有林地中濫墾地訂立租地契約遭拒絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00064', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '甲為中華民國國籍人士，其與A國籍乙在A國辦理結婚登記。嗣後乙持A國結婚證書向我國駐 A國代表處申請驗證結婚證書及核發依親居留簽證。然而我國駐A國代表處卻認為，甲與乙在面 談時對於結婚重要事實陳述不一致，因此駁回乙之簽證申請。依司法實務之見解，下列敘述何者 正確？', '["甲得以自己名義提起課予義務訴訟，請求發給乙簽證", "乙不具有我國國籍，因此無法提起行政救濟", "甲得以自己名義，提起撤銷訴願及撤銷訴訟，以資救濟", "因為甲本身並非依法得申請簽證之當事人，因此無法提起行政救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00065', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00066', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-114-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "1959a582ef2c", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "228", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00067', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲新買了一台重機，為顯現其壓車過彎的功力，邀集乙、丙、丁等好友
在週末假日到阿里山道路上飆車，因一群人競速影響往來行駛車輛，路
人遂通知警察。警察到場後，甲不理取締，加速衝撞警察離去，造成其
中一位警察受傷。因警方已記下甲車牌號碼，一日後依紀錄找到甲，開
罰單並吊扣其牌照。甲心想新的重機不開可惜，心生一計，影印牌照，
在繳交牌照後，黏貼於重機原掛牌照處，仍騎車上路。請問甲的行為如
何論處？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00068', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲至夜店飲酒，見乙落單，且喝到斷片，不省人事，假藉幫忙叫車送乙
回家，將乙帶回住處。趁機脫下乙的衣褲性交，並將性交過程錄影。第
二日乙清醒，知道自己前開情形，揚言告甲。甲拿出性交影片宣稱，如
果乙敢提告，甲就將前開性交影片上傳社群媒體。乙因心裡害怕遂未告
甲，但甲仍然將影片上傳其臉書，誇耀其性能力。請問甲的行為如何論
處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00069', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲為某詐欺集團首腦，製作交戰手冊，吸收乙、丙、丁參加，訓練其話
術，由乙先打電話給被害人，告訴他們其銀行戶頭涉及洗錢被凍結，須
由地檢署監管，再派遣丙佯裝地檢署之檢察官陪同被害人至銀行領款，
而丁則負責在社群媒體上刊登廣告，吸引投資人投資不存在之虛偽公
司。前後共獲利新臺幣（下同）五千萬元。甲將其中五百萬元分給丙，
兩百萬元分給丁，一千萬元轉匯給在酒店上班的女友 A（知情此乃詐欺
所得）。丙以該筆款項作為頭期款買房，丁則將分得之款項交給不知情兒
子 B，B 付給代辦留學公司 C。請問甲、乙、丙、丁之行為如何論處？
又如何沒收犯罪所得？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00070', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-916530c6', 'sub-heelevel3-6e2f88c7-01', NULL, 'essay', '甲為逼其夫 A與其離婚，商請友人醫生乙做成驗傷診斷證明書，並唆使
其妹妹丙出庭作證，提告 A 對其毆打（事實上無此情形）。事後丙經具
結後陳述其親眼見到 A多次毆打甲，致法院採納前開證據，判決A傷害
罪成立。請問甲、乙、丙的行為如何論處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "80f7e5b07803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1014", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00071', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-113-e733516d', 'sub-heelevel3-6e2f88c7-02', NULL, 'essay', '甲為 17歲之未成年人，與乙發生車禍。甲列乙為被告，於民國（下同）
113 年 5 月 1日起訴請求法院判命乙應賠償甲新臺幣（下同）300萬元，
並經其法定代理人丙合法代理，其理由略為：甲於 111 年 6 月 1 日與乙
發生車禍，因乙超速造成甲受傷嚴重，為此請求損害賠償300萬元。乙
則否認其有過失，並抗辯原告之請求概無理由，請求法院駁回原告之訴。
問：
經第一審法院審理半年後，甲於第二次言詞辯論期日中始擴張聲明為
400 萬元，是否合法？如法院從甲之陳述中已知車禍發生之時日，而
認擴張請求部分可能罹於時效時，應如何處理？（10分）
於言詞辯論期日中，乙提出反訴，列甲及丙為反訴之共同被告，主張
甲為無照駕駛，請求甲、丙就該次車禍連帶賠償乙 200萬元，受訴法
院應否准許反訴之提出？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:44+00:00", "source_pdf_sha1": "934f5381fdcb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1012", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL)
